    at::Tensor y = at::empty({x.size(0), weight.size(0),
                              x.size(2) - weight.size(2) + 1,
                              x.size(3) - weight.size(3) + 1},
                             x.options());
    if (bias_opt.has_value()) {
        EXEC_NPU_CMD(aclnnConv2dReluHardSwishCustom, x, weight, bias_opt.value(), y);
    } else {
        // Pass an undefined tensor for optional bias
        at::Tensor empty_bias;
        EXEC_NPU_CMD(aclnnConv2dReluHardSwishCustom, x, weight, empty_bias, y);
    }
    return y;
}

